class Solution:
    def zigZagArrays(self, n, l, r):
        MOD = 10**9 + 7
        m = r - l + 1
        size = 2 * m
        def matmul(A, B):
            C = [[0] * size for _ in range(size)]
            for i in range(size):
                Ai = A[i]
                Ci = C[i]
                for k in range(size):
                    a = Ai[k]
                    if a:
                        Bk = B[k]
                        for j in range(size):
                            Ci[j] = (Ci[j] + a * Bk[j]) % MOD
            return C
        T = [[0] * size for _ in range(size)]
        for i in range(m):
            for j in range(i):
                T[i][m + j] = 1
            for j in range(i + 1, m):
                T[m + i][j] = 1
        R = [[1 if i == j else 0 for j in range(size)] for i in range(size)]
        e = n - 1
        base = T
        while e > 0:
            if e & 1:
                R = matmul(R, base)
            base = matmul(base, base)
            e >>= 1
        vec = [1] * size
        total = 0
        for i in range(size):
            s = 0
            Ri = R[i]
            for j in range(size):
                s = (s + Ri[j] * vec[j]) % MOD
            total = (total + s) % MOD
        return total

