var zigZagArrays = function(n, l, r) {
    const MOD = 1000000007n;
    const m = r - l + 1;
    const size = 2 * m;
    function matmul(A, B) {
        const C = Array.from({ length: size }, () => new Array(size).fill(0n));
        for (let i = 0; i < size; i++) {
            for (let k = 0; k < size; k++) {
                const a = A[i][k];
                if (a !== 0n) {
                    const Bk = B[k];
                    const Ci = C[i];
                    for (let j = 0; j < size; j++) Ci[j] = (Ci[j] + a * Bk[j]) % MOD;
                }
            }
        }
        return C;
    }
    const T = Array.from({ length: size }, () => new Array(size).fill(0n));
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < i; j++) T[i][m + j] = 1n;
        for (let j = i + 1; j < m; j++) T[m + i][j] = 1n;
    }
    let R = Array.from({ length: size }, (_, i) => Array.from({ length: size }, (_, j) => (i === j ? 1n : 0n)));
    let e = n - 1;
    let base = T;
    while (e > 0) {
        if (e & 1) R = matmul(R, base);
        base = matmul(base, base);
        e = Math.floor(e / 2);
    }
    const vec = new Array(size).fill(1n);
    let total = 0n;
    for (let i = 0; i < size; i++) {
        let s = 0n;
        for (let j = 0; j < size; j++) s = (s + R[i][j] * vec[j]) % MOD;
        total = (total + s) % MOD;
    }
    return Number(total);
};
